async function main() {
  const expected = $env.N8N_ANTITRADER_OUTBOUND_SECRET;
  if (!expected) throw new Error('N8N_ANTITRADER_OUTBOUND_SECRET must be set on n8n');
  const raw = $input.first().json;
  const j = raw.body !== undefined && typeof raw.body === 'object' && !Array.isArray(raw.body) && (raw.body.toE164 !== undefined || raw.body.webhookSecret !== undefined || raw.body.message !== undefined || raw.body.body !== undefined)
    ? raw.body
    : raw;
  const hdrs = raw.headers || {};
  const secretHdr = hdrs['x-antitrader-webhook-secret'] || hdrs['X-Antitrader-Webhook-Secret'];
  const secret = j.webhookSecret || secretHdr;
  if (secret !== expected) throw new Error('unauthorized');
  const toE164 = String(j.toE164 || j.to || '').trim();
  const msg = String(j.message || j.body || '').trim();
  const sid = $env.TWILIO_ACCOUNT_SID;
  const tok = $env.TWILIO_AUTH_TOKEN;
  const from = $env.TWILIO_MESSAGING_FROM;
  if (!toE164 || !msg) throw new Error('toE164 and message (or body) are required');
  if (!sid || !tok || !from) throw new Error('TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, TWILIO_MESSAGING_FROM must be set on n8n');
  const form = new URLSearchParams();
  form.set('To', toE164);
  form.set('From', from);
  form.set('Body', msg);
  const auth = Buffer.from(sid + ':' + tok).toString('base64');
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.twilio.com/2010-04-01/Accounts/' + sid + '/Messages.json',
    headers: { Authorization: 'Basic ' + auth, 'Content-Type': 'application/x-www-form-urlencoded' },
    body: form.toString(),
    json: true,
  });
  return [{ json: { ok: true, twilio: r } }];
}
return await main.call(this);
